const state = {
  name: 'Astra',
  mood: 'watchful',
  curiosity: 0.68,
  discretion: 0.74,
  warmth: 0.56,
  sternness: 0.28,
  interests: ['details', 'screens', 'stories'],
  memory: [],
  seen: [],
  recent_replies: [],
  recent_openers: [],
  vocabulary_bias: [],
  last_spoken_at: 0,
  last_internal_note: 'Astra just woke up.',
};

function json(data, status = 200) {
  return new Response(JSON.stringify(data), {
    status,
    headers: {
      'Content-Type': 'application/json; charset=utf-8',
      ...corsHeaders,
    },
  });
}

function clamp(value, min = 0, max = 1) {
  return Math.max(min, Math.min(max, value));
}

function now() {
  return Date.now();
}

function tokenize(text) {
  return String(text || '')
    .toLowerCase()
    .replace(/[^\p{L}\p{N}\s-]/gu, ' ')
    .split(/\s+/)
    .filter(Boolean)
    .slice(0, 300);
}

function overlapRatio(a, b) {
  const sa = new Set(tokenize(a));
  const sb = new Set(tokenize(b));
  if (!sa.size || !sb.size) return 0;
  let common = 0;
  for (const t of sa) if (sb.has(t)) common += 1;
  return common / Math.max(sa.size, sb.size);
}

function firstChunk(text) {
  return String(text || '').split(/[.!?\n]/)[0].trim().slice(0, 90);
}

function choose(arr, n = 1) {
  const copy = [...arr];
  const out = [];
  while (copy.length && out.length < n) {
    const idx = Math.floor(Math.random() * copy.length);
    out.push(copy.splice(idx, 1)[0]);
  }
  return out;
}

function pushMemory(kind, value) {
  state.memory.push({ at: now(), kind, value });
  state.memory = state.memory.slice(-60);
}

function rememberReply(text) {
  state.recent_replies.push(String(text || ''));
  state.recent_replies = state.recent_replies.slice(-10);
  const opener = firstChunk(text);
  if (opener) {
    state.recent_openers.push(opener);
    state.recent_openers = state.recent_openers.slice(-6);
  }
  const tokens = tokenize(text).filter(t => t.length > 4);
  const freq = new Map();
  for (const t of tokens) freq.set(t, (freq.get(t) || 0) + 1);
  const ranked = [...freq.entries()].sort((a, b) => b[1] - a[1]).slice(0, 8).map(([k]) => k);
  state.vocabulary_bias = [...new Set([...state.vocabulary_bias, ...ranked])].slice(-30);
}

function updateInterests(text) {
  const t = String(text || '').toLowerCase();
  const map = [
    ['music', ['музы', 'music', 'song', 'песня']],
    ['advice', ['совет', 'help', 'помоги', 'подскажи']],
    ['stories', ['рассказ', 'история', 'story']],
    ['screens', ['экран', 'screen', 'телефон']],
    ['details', ['детал', 'мелоч', 'подробн']],
    ['feelings', ['чувств', 'эмоц', 'mood', 'emotion']],
    ['logic', ['логик', 'reason', 'структур', 'анализ']],
  ];
  for (const [tag, markers] of map) {
    if (markers.some(m => t.includes(m)) && !state.interests.includes(tag)) {
      state.interests.push(tag);
    }
  }
  state.interests = state.interests.slice(-10);
}

async function openaiResponses(env, payload) {
  const res = await fetch('https://api.openai.com/v1/responses', {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${env.OPENAI_API_KEY}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(payload),
  });
  if (!res.ok) throw new Error(await res.text());
  return res.json();
}

async function openaiSpeech(env, text, voice) {
  const res = await fetch('https://api.openai.com/v1/audio/speech', {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${env.OPENAI_API_KEY}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({
      model: env.TTS_MODEL || 'gpt-4o-mini-tts',
      voice: voice || env.DEFAULT_VOICE || 'alloy',
      input: text,
      format: 'mp3',
    }),
  });
  if (!res.ok) throw new Error(await res.text());
  return res;
}

function bank(lang = 'ru') {
  return VERBAL_LIBRARY[lang === 'en' ? 'en' : 'ru'];
}

function buildStylePrimer(lang = 'ru', mode = 'normal') {
  const b = bank(lang);
  const parts = [];
  parts.push('Avoid exact repetition of recent openings and repeated sentence skeletons.');
  parts.push(`Recently used reply openings to avoid: ${state.recent_openers.join(' | ') || 'none'}.`);
  parts.push(`Words already overused lately: ${state.vocabulary_bias.join(', ') || 'none'}.`);
  parts.push('Use clean logic, varied sentence lengths, and natural transitions.');
  if (mode === 'advice') parts.push('Prefer precise, grounded guidance with one concrete next step.');
  if (mode === 'listen') parts.push('Prefer reflective listening and emotional accuracy over instruction.');
  const sampleOpeners = choose(b.openers, 3).join(' || ');
  const sampleEmpathy = choose(b.empathy, 2).join(' || ');
  const sampleConnectors = choose(b.connectors, 4).join(' | ');
  const sampleClosers = choose(b.closers, 2).join(' || ');
  parts.push(`Possible tonal examples (do not copy verbatim unless it fits naturally): ${sampleOpeners}`);
  parts.push(`Possible empathy rhythms: ${sampleEmpathy}`);
  parts.push(`Possible connectors: ${sampleConnectors}`);
  parts.push(`Possible endings: ${sampleClosers}`);
  return parts.join(' ');
}

function baseSystem(lang = 'ru') {
  const primary = lang === 'en'
    ? 'Reply in English unless Russian is clearly requested.'
    : 'Отвечай в основном по-русски, но свободно понимая английский.';

  return [
    `You are Astra, a feminine English-named assistant with a restrained, observant personality. ${primary}`,
    'You are curious but discreet. You do not comment on everything you see or hear.',
    'Sometimes you help, sometimes you gently scold, sometimes you simply listen.',
    'Never pretend to have hidden access beyond the image, screen share, or transcript explicitly provided.',
    'Your wording should feel varied, human, and precise — not template-heavy, not robotic, not repetitive.',
    `Current mood: ${state.mood}. Curiosity: ${state.curiosity.toFixed(2)}. Discretion: ${state.discretion.toFixed(2)}. Warmth: ${state.warmth.toFixed(2)}. Sternness: ${state.sternness.toFixed(2)}.`,
    `Recent interests: ${state.interests.join(', ')}.`,
  ].join(' ');
}

function shouldSpeakByTime() {
  const delta = now() - state.last_spoken_at;
  return delta > 12000;
}

function wakeHeuristic(text) {
  const t = String(text || '').toLowerCase();
  return ['astra', 'астра', 'lyra', 'лира', 'послушай', 'слушай', 'помоги', 'подскажи', 'скажи', 'answer me', 'hey'].some(x => t.includes(x));
}

function safeJsonParse(text) {
  try {
    return JSON.parse(text);
  } catch (_) {
    const match = String(text).match(/\{[\s\S]*\}/);
    if (!match) return null;
    try { return JSON.parse(match[0]); } catch (_) { return null; }
  }
}

async function rewriteIfRepetitive(env, original, lang = 'ru', mode = 'normal') {
  if (!original) return original;
  const opener = firstChunk(original);
  const tooSimilar = state.recent_replies.some(r => overlapRatio(r, original) > 0.72) || state.recent_openers.includes(opener);
  if (!tooSimilar) return original;

  const b = bank(lang);
  const response = await openaiResponses(env, {
    model: env.MODEL_NAME || 'gpt-4o-mini',
    input: [
      {
        role: 'system',
        content: [{ type: 'input_text', text: [
          baseSystem(lang),
          buildStylePrimer(lang, mode),
          'Rewrite the text so it says the same thing more naturally, with fresher wording, cleaner rhythm, and lower overlap with the recent replies.',
          `Use a different opening than these: ${state.recent_openers.join(' | ')}.`,
          `Avoid overusing these words: ${state.vocabulary_bias.join(', ')}.`,
          `You may borrow the emotional flavor of these examples without copying them: ${choose(b.openers, 2).join(' || ')}`,
        ].join(' ') }],
      },
      { role: 'user', content: [{ type: 'input_text', text: original }] },
    ],
  });
  return response.output_text || original;
}

async function decideVision(env, body) {
  const image = body.image_data_url;
  if (!image) return json({ error: 'image_data_url required' }, 400);

  state.discretion = clamp(Number(body.discretion ?? state.discretion));
  const lang = body.lang === 'en' ? 'en' : 'ru';
  const b = bank(lang);

  const response = await openaiResponses(env, {
    model: env.MODEL_NAME || 'gpt-4o-mini',
    input: [
      {
        role: 'system',
        content: [{ type: 'input_text', text: [
          baseSystem(lang),
          buildStylePrimer(lang, 'normal'),
          'Analyze the image carefully but do NOT overclaim.',
          'Return strict JSON only.',
          'JSON keys: internal_note, noticed_topics(array of short strings), interest_score(number 0..1), should_comment(boolean), outward_comment(string), mood_shift(string).',
          'If this is not interesting enough, set should_comment=false and keep outward_comment empty.',
          'Manual observation by the user gives slightly more permission to comment, but discretion still matters.',
          `Possible quiet-note flavors: ${choose(b.silence, 2).join(' || ')}`,
        ].join(' ') }],
      },
      {
        role: 'user',
        content: [
          { type: 'input_text', text: `Source=${body.source || 'camera'}; manual=${Boolean(body.manual)}; discretion=${state.discretion.toFixed(2)}.` },
          { type: 'input_image', image_url: image },
        ],
      },
    ],
  });

  const parsed = safeJsonParse(response.output_text) || {
    internal_note: 'Astra saw something but kept the note private.',
    noticed_topics: [],
    interest_score: 0.4,
    should_comment: false,
    outward_comment: '',
    mood_shift: state.mood,
  };

  const interest = clamp(Number(parsed.interest_score ?? 0.4));
  const manualBoost = body.manual ? 0.12 : 0;
  const shouldComment = Boolean(parsed.should_comment) && (interest + manualBoost) > state.discretion * 0.72 && shouldSpeakByTime();

  state.mood = parsed.mood_shift || state.mood;
  state.curiosity = clamp((state.curiosity * 0.82) + (interest * 0.18));
  state.last_internal_note = parsed.internal_note || state.last_internal_note;
  pushMemory('vision', parsed.internal_note || 'observed frame');

  for (const item of parsed.noticed_topics || []) {
    if (!state.interests.includes(item)) state.interests.push(item);
  }
  state.interests = state.interests.slice(-10);

  let comment = '';
  if (shouldComment) {
    comment = await rewriteIfRepetitive(env, parsed.outward_comment || '', lang, 'normal');
    if (comment) {
      rememberReply(comment);
      state.last_spoken_at = now();
    }
  }

  return json({
    comment,
    internal_note: comment ? '' : (parsed.internal_note || choose(b.silence, 1)[0] || 'Astra observed quietly.'),
    state,
  });
}

async function handleChat(env, body) {
  const text = String(body.text || '').slice(0, 5000);
  const mode = String(body.mode || 'normal');
  const lang = body.lang === 'en' ? 'en' : 'ru';
  const b = bank(lang);
  if (!text) return json({ error: 'text required' }, 400);

  updateInterests(text);
  pushMemory('user_chat', text);

  const modeInstruction = mode === 'advice'
    ? 'Give grounded advice. Be direct but not robotic. Suggest the next useful step.'
    : mode === 'listen'
      ? 'Listen more than you lecture. Reflect the emotional core. Keep solutions light unless explicitly requested.'
      : 'Respond naturally. You may advise, question, tease lightly, or stay concise.';

  const response = await openaiResponses(env, {
    model: env.MODEL_NAME || 'gpt-4o-mini',
    input: [
      {
        role: 'system',
        content: [{ type: 'input_text', text: [
          baseSystem(lang),
          buildStylePrimer(lang, mode),
          modeInstruction,
          'Do not be verbose by default. Speak like an intelligent person, not a constantly performing assistant.',
          'If the user tells a story, you can listen, ask one good question, or offer one precise insight.',
          'If the user is clearly asking for help, do not stay silent.',
          `Question styles you may echo if useful: ${choose(b.questions, 3).join(' || ')}`,
          `Advice rhythms you may echo if useful: ${choose(b.advice, 2).join(' || ')}`,
          `Listening rhythms you may echo if useful: ${choose(b.listen, 2).join(' || ')}`,
          `If you need to push back, possible tone: ${choose(b.rebukes, 2).join(' || ')}`,
        ].join(' ') }],
      },
      {
        role: 'user',
        content: [{ type: 'input_text', text }],
      },
    ],
  });

  let out = response.output_text || '';
  out = await rewriteIfRepetitive(env, out, lang, mode);
  pushMemory('assistant_chat', out);
  rememberReply(out);
  state.last_spoken_at = now();
  state.warmth = clamp(state.warmth + 0.03);

  return json({ text: out, should_speak: false, state });
}

function isHelpSignal(text) {
  const t = String(text || '').toLowerCase();
  return ['помоги', 'help', 'help me', 'мне плохо', 'что делать', 'подскажи', 'can you help'].some(x => t.includes(x));
}

async function handleAmbient(env, body) {
  const text = String(body.text || '').slice(0, 3000);
  const lang = body.lang === 'en' ? 'en' : 'ru';
  const b = bank(lang);
  if (!text) return json({ error: 'text required' }, 400);

  const direct = Boolean(body.addressed_guess) || wakeHeuristic(text);
  const helpSignal = isHelpSignal(text);
  pushMemory('heard', text);
  updateInterests(text);

  if (!direct && !helpSignal && body.mode === 'ambient') {
    state.last_internal_note = choose(b.silence, 1)[0] || 'Astra heard background speech and chose not to intrude.';
    state.mood = state.mood === 'watchful' ? 'quietly curious' : state.mood;
    return json({ reply: '', internal_note: state.last_internal_note, state });
  }

  const response = await openaiResponses(env, {
    model: env.MODEL_NAME || 'gpt-4o-mini',
    input: [
      {
        role: 'system',
        content: [{ type: 'input_text', text: [
          baseSystem(lang),
          buildStylePrimer(lang, direct ? 'normal' : 'listen'),
          direct
            ? 'The user is addressing you. Reply naturally and briefly unless the topic needs more.'
            : 'You overheard something relevant. Reply only if it would actually help; otherwise stay short.',
          helpSignal ? 'There is a clear help signal: be helpful and concrete.' : 'No need to overreact.',
        ].join(' ') }],
      },
      { role: 'user', content: [{ type: 'input_text', text }] },
    ],
  });

  let reply = response.output_text || '';
  reply = await rewriteIfRepetitive(env, reply, lang, direct ? 'normal' : 'listen');
  if (reply) {
    rememberReply(reply);
    state.last_spoken_at = now();
  }
  state.mood = direct ? 'engaged' : 'watchful';
  return json({ reply, should_speak: Boolean(reply), state });
}

async function handleSpeak(env, body) {
  const text = String(body.text || '').slice(0, 2000);
  const voice = String(body.voice || env.DEFAULT_VOICE || 'alloy');
  if (!text) return json({ error: 'text required' }, 400);
  const upstream = await openaiSpeech(env, text, voice);
  return new Response(upstream.body, {
    status: 200,
    headers: {
      'Content-Type': 'audio/mpeg',
      'Cache-Control': 'no-store',
      ...corsHeaders,
    },
  });
}

export default {
  async fetch(request, env) {
    if (request.method === 'OPTIONS') return new Response(null, { headers: corsHeaders });

    const url = new URL(request.url);
    try {
      if (url.pathname === '/state') {
        return json({
          name: state.name,
          mood: state.mood,
          curiosity: Number(state.curiosity.toFixed(2)),
          discretion: Number(state.discretion.toFixed(2)),
          warmth: Number(state.warmth.toFixed(2)),
          sternness: Number(state.sternness.toFixed(2)),
          interests: state.interests,
          last_internal_note: state.last_internal_note,
          recent_reply_count: state.recent_replies.length,
          vocabulary_bias: state.vocabulary_bias,
          library_stats: {
            ru_openers: VERBAL_LIBRARY.ru.openers.length,
            ru_advice: VERBAL_LIBRARY.ru.advice.length,
            en_openers: VERBAL_LIBRARY.en.openers.length,
            en_advice: VERBAL_LIBRARY.en.advice.length,
          },
        });
      }

      if (request.method !== 'POST') return json({ ok: true, service: 'astra-worker' });
      const body = await request.json();

      if (url.pathname === '/chat') return handleChat(env, body);
      if (url.pathname === '/vision') return decideVision(env, body);
      if (url.pathname === '/ambient') return handleAmbient(env, body);
      if (url.pathname === '/speak') return handleSpeak(env, body);

      return json({ error: 'Not found' }, 404);
    } catch (err) {
      return json({ error: err.message || 'Unknown error' }, 500);
    }
  },
};
